import React, { useState } from "react";

const bereshitCard = {
  name: "Bereshit",
  questions: [
    {
      question: "What day was Adam born?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question: "What day was not 'good' but 'very' good?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question:
        "Where do we see adding is sometimes subtracting?",
      answer:
        "Adam added 'don't touch' the tree. The snake used this to fool Chava.",
      points: 20,
    },
  ],
};

function CardQA() {
  const [currentQ, setCurrentQ] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);
  // Track which questions were accepted correct: array of booleans
  const [accepted, setAccepted] = useState(
    Array(bereshitCard.questions.length).fill(false)
  );

  const toggleAnswer = () => setShowAnswer((v) => !v);

  const acceptCorrect = () => {
    setAccepted((prev) => {
      const copy = [...prev];
      copy[currentQ] = true;
      return copy;
    });
  };

  const prevQuestion = () => {
    setShowAnswer(false);
    setCurrentQ((i) => (i > 0 ? i - 1 : i));
  };

  const nextQuestion = () => {
    setShowAnswer(false);
    setCurrentQ((i) =>
      i < bereshitCard.questions.length - 1 ? i + 1 : i
    );
  };

  const totalPoints = accepted.reduce(
    (sum, val, i) => (val ? sum + bereshitCard.questions[i].points : sum),
    0
  );

  const allCorrect = accepted.every((val) => val === true);

  return (
    <div style={styles.container}>
      <h2>{bereshitCard.name} Card Q&A</h2>
      <p>
        Question {currentQ + 1} of {bereshitCard.questions.length}
      </p>
      <div style={styles.questionBox}>
        <p style={{ fontWeight: "bold" }}>
          {bereshitCard.questions[currentQ].question}
        </p>
        {showAnswer ? (
          <p style={styles.answer}>{bereshitCard.questions[currentQ].answer}</p>
        ) : (
          <button onClick={toggleAnswer} style={styles.button}>
            Reveal Answer
          </button>
        )}
      </div>
      <div style={{ marginTop: 10 }}>
        <button
          onClick={prevQuestion}
          disabled={currentQ === 0}
          style={styles.button}
        >
          Previous Question
        </button>
        <button
          onClick={nextQuestion}
          disabled={currentQ === bereshitCard.questions.length - 1}
          style={{ ...styles.button, marginLeft: 10 }}
        >
          Next Question
        </button>
      </div>

      <div style={{ marginTop: 20 }}>
        {!accepted[currentQ] && showAnswer && (
          <button onClick={acceptCorrect} style={styles.acceptButton}>
            Accept Correct (Add {bereshitCard.questions[currentQ].points} Zchut)
          </button>
        )}
        {accepted[currentQ] && (
          <p style={{ color: "green", fontWeight: "bold" }}>
            Accepted Correct ✔
          </p>
        )}
      </div>

      <div style={{ marginTop: 30 }}>
        <p>
          Total Zchut Points Earned: <strong>{totalPoints}</strong>
        </p>

        {allCorrect ? (
          <p style={{ color: "blue", fontWeight: "bold" }}>
            All questions answered correctly! You can proceed to the next card.
          </p>
        ) : (
          <p>
            You can finish now with current points or continue answering.
          </p>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    maxWidth: 500,
    margin: "20px auto",
    padding: 20,
    border: "2px solid #333",
    borderRadius: 10,
    backgroundColor: "#fefefe",
    textAlign: "center",
  },
  questionBox: {
    marginTop: 20,
    padding: 15,
    border: "1px solid #999",
    borderRadius: 8,
    backgroundColor: "#f9f9f9",
  },
  answer: {
    marginTop: 10,
    fontStyle: "italic",
    color: "#007700",
    fontWeight: "bold",
  },
  button: {
    padding: "8px 14px",
    marginTop: 10,
    fontSize: 14,
    borderRadius: 6,
    border: "none",
    cursor: "pointer",
    backgroundColor: "#007bff",
    color: "white",
  },
  acceptButton: {
    padding: "10px 18px",
    fontSize: 16,
    marginTop: 15,
    borderRadius: 8,
    border: "none",
    cursor: "pointer",
    backgroundColor: "#28a745",
    color: "white",
  },
};

export default CardQA;
